{
  "terms": [
    {
      "term": "Resistance (R)",
      "simpleDefinition": "The physical opposition to the flow of electric current through a conductor, measured in Ohms (Ω).",
      "anchor": "Think of it as electrical friction that slows down the flow of electrons.",
      "misconception": "Believing only resistors have resistance; in reality, every cable and connection in a circuit has some level of resistance."
    },
    {
      "term": "Resistivity (ρ)",
      "simpleDefinition": "A constant value representing how strongly a specific material opposes current flow, regardless of its shape.",
      "anchor": "The 'DNA' of a material; copper has a low resistivity, while steel has a higher one.",
      "misconception": "Thinking resistivity changes if you cut a wire shorter; resistivity is a fixed property of the material itself, not the object's size."
    },
    {
      "term": "Voltage Drop",
      "simpleDefinition": "The loss of electrical pressure (potential) as current flows through a resistance.",
      "anchor": "Like the drop in water pressure from one end of a long hose to the other.",
      "misconception": "Thinking voltage drop is 'lost' electricity; it is actually electrical energy being converted into heat energy."
    },
    {
      "term": "Ohm (Ω)",
      "simpleDefinition": "The standard unit of measurement for electrical resistance.",
      "anchor": "The 'ruler' we use to measure how much a circuit fights back against current.",
      "misconception": "Confusing Ohms with Volts; Ohms measure the opposition, while Volts measure the push."
    },
    {
      "term": "Ohm-metre (Ωm)",
      "simpleDefinition": "The unit of measurement used specifically for resistivity.",
      "anchor": "The specific unit used to compare the conductive quality of different raw materials.",
      "misconception": "Using Ohms and Ohm-metres interchangeably; Ohms are for components, Ohm-metres are for material properties."
    }
  ],
  "anchorPhrases": [
    "Resistance is the opposition to current flow.",
    "Resistivity is a property of the material itself.",
    "Voltage drop is the reduction in electrical potential.",
    "Every conductor has some resistance.",
    "Resistivity is the resistance of a unit cube of material."
  ],
  "misconceptionTargets": [
    "Resistivity changes with the length of the wire.",
    "Voltage drop means electricity has disappeared from the circuit.",
    "Resistance and resistivity are the same thing.",
    "Voltage drop only occurs in the load, not the cables."
  ]
}

{
  "teachChecks": [
    {
      "title": "Defining Resistance (R)",
      "basicQuestions": [
        {
          "questionText": "What is the technical term for the physical opposition that a material offers to the flow of electric current?",
          "answerGuidance": [
            "Resistance",
            "R",
            "Electrical opposition"
          ],
          "hint": "It is the measure of how much a circuit 'fights back' against current.",
          "sourceTeachingPointIds": [
            "TP1"
          ]
        },
        {
          "questionText": "What is the standard unit of measurement used for electrical resistance?",
          "answerGuidance": [
            "Ohm",
            "Ohms",
            "Ω"
          ],
          "hint": "This unit is named after a famous scientist and uses a Greek symbol.",
          "sourceTeachingPointIds": [
            "TP2"
          ]
        },
        {
          "questionText": "In electrical circuits, which parts besides specific components like resistors possess resistance?",
          "answerGuidance": [
            "Every part",
            "Cables and connections",
            "All conductive materials",
            "The whole circuit"
          ],
          "hint": "Think about whether resistance is limited to just one type of component.",
          "sourceTeachingPointIds": [
            "TP4"
          ]
        }
      ],
      "deeperQuestionText": "Why is it technically accurate to describe resistance as 'electrical friction' when considering the movement of electrons?",
      "deeperAnswerGuidance": [
        "It slows down the movement of electrons",
        "It opposes the flow of current",
        "Energy is used up to overcome the opposition",
        "It behaves like physical friction by resisting motion"
      ],
      "deeperSourceTeachingPointIds": [
        "TP1",
        "TP3"
      ],
      "hint": "Consider what happens to the speed and energy of electrons as they move through a conductor."
    },
    {
      "title": "Defining Resistivity (ρ)",
      "basicQuestions": [
        {
          "questionText": "What is the name of the constant value that describes how strongly a specific material opposes current flow regardless of its shape?",
          "answerGuidance": [
            "Resistivity",
            "ρ",
            "Rho"
          ],
          "hint": "This is a property of the material itself, like copper or aluminum.",
          "sourceTeachingPointIds": [
            "TP1"
          ]
        },
        {
          "questionText": "What is the specific unit of measurement used for resistivity?",
          "answerGuidance": [
            "Ohm-metre",
            "Ωm",
            "Ohm-metres"
          ],
          "hint": "It combines the unit for resistance with a unit of length.",
          "sourceTeachingPointIds": [
            "TP2"
          ]
        },
        {
          "questionText": "Which Greek letter is used as the symbol for resistivity in electrical science?",
          "answerGuidance": [
            "Rho",
            "ρ"
          ],
          "hint": "It looks like a lowercase 'p'.",
          "sourceTeachingPointIds": [
            "TP2"
          ]
        }
      ],
      "deeperQuestionText": "If you have two different sized blocks of pure copper, why is the resistivity value exactly the same for both?",
      "deeperAnswerGuidance": [
        "Resistivity is an intrinsic property of the material",
        "It does not change based on shape or size",
        "It is a constant for that specific substance",
        "It is defined by the material type rather than dimensions"
      ],
      "deeperSourceTeachingPointIds": [
        "TP1",
        "TP4"
      ],
      "hint": "Think about whether the 'type' of material has changed just because the size changed."
    },
    {
      "title": "Resistance vs. Resistivity",
      "basicQuestions": [
        {
          "questionText": "If a copper wire is cut in half, which property of that specific piece of wire will decrease?",
          "answerGuidance": [
            "Resistance",
            "R"
          ],
          "hint": "Think about which value depends on the length of the path.",
          "sourceTeachingPointIds": [
            "TP1",
            "TP2"
          ]
        },
        {
          "questionText": "Which property of a conductor is determined solely by the type of material it is made from?",
          "answerGuidance": [
            "Resistivity",
            "ρ",
            "Rho"
          ],
          "hint": "This is the 'DNA' of the material.",
          "sourceTeachingPointIds": [
            "TP3"
          ]
        },
        {
          "questionText": "Besides length and resistivity, what is the third physical factor that affects the total resistance of a conductor?",
          "answerGuidance": [
            "Cross-sectional area",
            "Area",
            "Thickness"
          ],
          "hint": "This refers to the size of the 'face' of the wire if you cut through it.",
          "sourceTeachingPointIds": [
            "TP1"
          ]
        }
      ],
      "deeperQuestionText": "How does the distinction between resistance and resistivity help an electrician understand the difference between a material's quality and a component's dimensions?",
      "deeperAnswerGuidance": [
        "Resistivity identifies how good a conductor the substance is",
        "Resistance is the final result of how that material is shaped",
        "Changing dimensions changes resistance but not the material quality",
        "Resistivity is a fixed constant while resistance is variable based on size"
      ],
      "deeperSourceTeachingPointIds": [
        "TP3",
        "TP4"
      ],
      "hint": "Consider which term describes the 'raw material' and which describes the 'finished wire'."
    },
    {
      "title": "The Concept of Voltage Drop",
      "basicQuestions": [
        {
          "questionText": "What term is used to describe the reduction in electrical potential as current flows through a resistance?",
          "answerGuidance": [
            "Voltage drop",
            "Vd"
          ],
          "hint": "It is the loss of 'pressure' across a conductor.",
          "sourceTeachingPointIds": [
            "TP1"
          ]
        },
        {
          "questionText": "Into what form of energy is the electrical potential usually converted when a voltage drop occurs?",
          "answerGuidance": [
            "Heat",
            "Thermal energy"
          ],
          "hint": "Think about what happens to a wire when it resists current flow.",
          "sourceTeachingPointIds": [
            "TP3"
          ]
        },
        {
          "questionText": "Where does voltage drop occur in a circuit besides the intended load?",
          "answerGuidance": [
            "Every part with resistance",
            "Cables",
            "Supply conductors",
            "Connections"
          ],
          "hint": "Does it only happen in the light bulb, or also in the wires leading to it?",
          "sourceTeachingPointIds": [
            "TP4"
          ]
        }
      ],
      "deeperQuestionText": "Why is it incorrect to say that voltage is 'lost' or 'disappears' when a voltage drop occurs in a long cable run?",
      "deeperAnswerGuidance": [
        "Energy is converted into another form",
        "It is transformed into heat energy",
        "It is used to overcome the resistance of the conductor",
        "The electrical potential is spent rather than destroyed"
      ],
      "deeperSourceTeachingPointIds": [
        "TP2",
        "TP3"
      ],
      "hint": "Think about the law of energy conservation and what happens to the 'spent' energy."
    },
    {
      "title": "The Link: Resistivity to Voltage Drop",
      "basicQuestions": [
        {
          "questionText": "Why is copper specifically chosen for most electrical wiring in terms of its material properties?",
          "answerGuidance": [
            "Low resistivity",
            "It has a low rho value"
          ],
          "hint": "Think about how its 'internal' resistance property affects the circuit.",
          "sourceTeachingPointIds": [
            "TP3"
          ]
        },
        {
          "questionText": "What happens to the amount of voltage drop if you switch to a cable material with a higher resistivity?",
          "answerGuidance": [
            "Increases",
            "Higher voltage drop",
            "It goes up"
          ],
          "hint": "Higher resistivity means more opposition to current.",
          "sourceTeachingPointIds": [
            "TP2"
          ]
        },
        {
          "questionText": "What is a practical consequence for equipment if the voltage drop in the supply cables is excessive?",
          "answerGuidance": [
            "Fail to operate correctly",
            "Operate unsafely",
            "Insufficient pressure to run",
            "Equipment failure"
          ],
          "hint": "Think about whether the device will have enough 'push' to work.",
          "sourceTeachingPointIds": [
            "TP4"
          ]
        }
      ],
      "deeperQuestionText": "How does the resistivity of a chosen material directly impact the efficiency of an electrical installation?",
      "deeperAnswerGuidance": [
        "Lower resistivity reduces unwanted resistance in cables",
        "Lower resistance results in less voltage drop",
        "Less voltage drop means less energy is wasted as heat",
        "It ensures more electrical potential reaches the intended equipment"
      ],
      "deeperSourceTeachingPointIds": [
        "TP1",
        "TP2",
        "TP3"
      ],
      "hint": "Connect the material property to the resistance, then to the energy loss in the cables."
    }
  ]
}

{
  "integrative": {
    "title": "Integrative Close: From Material to Voltage Drop",
    "objective": "Synthesize the relationship between material resistivity, conductor resistance, and the resulting voltage drop in a practical installation context.",
    "retrievalTextLines": [
      "Resistivity (ρ) is the intrinsic property of the material itself.",
      "Resistance (R) is the total opposition created by the material's resistivity and its physical dimensions.",
      "Voltage drop is the loss of electrical potential (pressure) as current overcomes resistance."
    ],
    "questionText": "An electrician is installing a very long cable run to a remote motor. Explain how the resistivity of the conductor material chosen (such as copper versus a higher-resistivity metal) determines the total resistance of the cable, and describe the resulting effect this has on the voltage available at the motor.",
    "answerGuidance": [
      "Higher resistivity in a material directly increases the total resistance of the cable run.",
      "As resistance increases, more electrical pressure is required to push current through the conductor.",
      "This results in a higher voltage drop along the cable, meaning less voltage (potential) is available to power the motor at the end of the run.",
      "The 'dropped' voltage is converted into heat energy within the conductor."
    ],
    "hint": "Link the material's 'DNA' (resistivity) to the total 'friction' (resistance) and explain what happens to the electrical 'pressure' by the time it reaches the motor."
  }
}

